/**
 * Scrambled FASTA Reassembly — real cancer-gene DNA through the wire
 * protocol.
 *
 * Reads every FASTA file in
 * `open-source/bitwise/datasets/cancer-genes/fasta/`, packs the bases
 * 2-bit (A=00, C=01, G=10, T=11, 4 bases/byte — the bitwise
 * convention), scrambles the byte order, and pushes both original and
 * scrambled streams through:
 *
 *    prism → settleByLane → ingestToKnotgraph → materializeIngest
 *
 * Reports, per gene:
 *   - base count, packed byte count
 *   - lane occupancy distribution
 *   - per-lane byte-multiset identity between original vs scrambled
 *   - knotgraph block count parity
 *   - DuckDB row parity
 *   - end-to-end throughput (MB/s)
 *
 * The aggregate claim: every gene reassembles identically at the lane
 * level regardless of arrival order. Scrambled KRAS → same settled
 * lanes as unscrambled KRAS. The wire is permutation-invariant; the
 * shape is in the content, not the stream order.
 *
 * Usage:
 *   cd open-source/gnosis
 *   node ./bin/gnode.js run scripts/benchmark-fasta-reassembly.ts
 */

import { readFileSync, readdirSync } from 'node:fs';
import { join, basename } from 'node:path';
import { createRawStream, settleByLane } from '../src/prismatic-refraction';
import {
  ingestToKnotgraph,
  KNOTGRAPH_DIMS,
  type IngestContext,
  type TenantId,
} from '../src/prismatic-refraction-knotgraph';
import { materializeIngest } from '../src/prismatic-refraction-duckdb';

// ─── Config ──────────────────────────────────────────────────────────

const FASTA_DIR =
  './open-source/bitwise/datasets/cancer-genes/fasta';
const K = 16; // lanes (knotgraph app-zone width)
const SCRAMBLE_SEED = 42;
const TENANT: TenantId = { hi: 0x1234_5678, lo: 0x9abc_def0 };
const CTX: IngestContext = {
  tenant: TENANT,
  typeTag: 0xdeadbeef,
  schemaKnotHash: 0xfacefeed,
  provenanceDid: 1,
  freshnessClock: 0,
};

// ─── FASTA parser (stdlib-only, no bioinformatics deps) ──────────────

/** Parse a FASTA file into its concatenated base sequence (uppercase,
 *  {A,C,G,T} only; any other char skipped). Headers are stripped. */
function parseFasta(text: string): string {
  const lines = text.split('\n');
  const out: string[] = [];
  for (const line of lines) {
    if (line.length === 0 || line[0] === '>' || line[0] === ';') continue;
    for (const c of line) {
      const up = c.toUpperCase();
      if (up === 'A' || up === 'C' || up === 'G' || up === 'T') out.push(up);
    }
  }
  return out.join('');
}

// ─── 2-bit packing (bitwise convention) ──────────────────────────────

/** Pack a sequence of bases into bytes, 4 bases per byte, MSB first.
 *  Matches `bw pack`: `ACGT` → `0b00_01_10_11` = 0x1B. Trailing partial
 *  byte is padded with 0 (A). */
function packBases2Bit(bases: string): Uint8Array {
  const n = Math.ceil(bases.length / 4);
  const out = new Uint8Array(n);
  for (let i = 0; i < bases.length; i++) {
    const base = bases[i]!;
    const code =
      base === 'A' ? 0 : base === 'C' ? 1 : base === 'G' ? 2 : /* T */ 3;
    const byteIndex = Math.floor(i / 4);
    const shift = (3 - (i % 4)) * 2;
    out[byteIndex] |= code << shift;
  }
  return out;
}

// ─── Deterministic Fisher-Yates scramble ─────────────────────────────

function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    return s;
  };
}

function scramble(bytes: Uint8Array, seed: number): Uint8Array {
  const out = new Uint8Array(bytes);
  const rng = lcg(seed);
  for (let i = out.length - 1; i > 0; i--) {
    const j = (rng() >>> 2) % (i + 1);
    const tmp = out[i]!;
    out[i] = out[j]!;
    out[j] = tmp;
  }
  return out;
}

// ─── Comparison helpers ──────────────────────────────────────────────

function bytesIdentical(a: Uint8Array, b: Uint8Array): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) if (a[i] !== b[i]) return false;
  return true;
}

function sortedBytesHash(payload: ReadonlyArray<number>): bigint {
  const sorted = [...payload].sort((x, y) => x - y);
  let h = 0xcbf29ce484222325n;
  const P = 0x100000001b3n;
  for (const b of sorted) {
    h = ((h ^ BigInt(b & 0xff)) * P) & 0xffffffffffffffffn;
  }
  return h & 0xffffffffffffn;
}

// ─── Per-gene processing ─────────────────────────────────────────────

interface GeneResult {
  readonly name: string;
  readonly bases: number;
  readonly packedBytes: number;
  readonly scrambleIdentityChanged: boolean;
  readonly lanesOccupied: number;
  readonly allLanesReassembled: boolean;
  readonly blockCountMatch: boolean;
  readonly rowCountMatch: boolean;
  readonly entityHashDiffers: boolean;
  readonly throughputMBs: number;
}

function processGene(filePath: string): GeneResult {
  const text = readFileSync(filePath, 'utf8');
  const bases = parseFasta(text);
  const packed = packBases2Bit(bases);
  const scrambled = scramble(packed, SCRAMBLE_SEED);

  const origStream = createRawStream(Array.from(packed));
  const scramStream = createRawStream(Array.from(scrambled));

  // End-to-end timing (both streams).
  const start = performance.now();
  const ingestOrig = ingestToKnotgraph(origStream, K, CTX);
  const ingestScram = ingestToKnotgraph(scramStream, K, CTX);
  const settledOrig = settleByLane([...ingestOrig.witness.settled]);
  const settledScram = settleByLane([...ingestScram.witness.settled]);
  const matOrig = materializeIngest(ingestOrig);
  const matScram = materializeIngest(ingestScram);
  const elapsedMs = performance.now() - start;

  // Lane reassembly check.
  const origByLane = new Map<number, number[]>();
  const scramByLane = new Map<number, number[]>();
  for (const s of settledOrig) origByLane.set(s.laneId, [...s.payload]);
  for (const s of settledScram) scramByLane.set(s.laneId, [...s.payload]);

  const allLanes = new Set<number>([...origByLane.keys(), ...scramByLane.keys()]);
  let allLanesReassembled = true;
  for (const lane of allLanes) {
    const o = origByLane.get(lane) ?? [];
    const s = scramByLane.get(lane) ?? [];
    if (o.length !== s.length) {
      allLanesReassembled = false;
      break;
    }
    if (sortedBytesHash(o) !== sortedBytesHash(s)) {
      allLanesReassembled = false;
      break;
    }
  }

  // Entity hash MUST differ between orig and scrambled (if both produced
  // ≥ 1 shard — within-lane byte order is different so FNV hashes differ).
  let entityHashDiffers = true;
  if (ingestOrig.blocks.length > 0 && ingestScram.blocks.length > 0) {
    let anyDiffers = false;
    const n = Math.min(ingestOrig.blocks.length, ingestScram.blocks.length);
    for (let i = 0; i < n; i++) {
      if (
        ingestOrig.blocks[i]!.dims[KNOTGRAPH_DIMS.ENTITY_ID] !==
        ingestScram.blocks[i]!.dims[KNOTGRAPH_DIMS.ENTITY_ID]
      ) {
        anyDiffers = true;
        break;
      }
    }
    entityHashDiffers = anyDiffers;
  }

  return {
    name: basename(filePath, '.fasta'),
    bases: bases.length,
    packedBytes: packed.length,
    scrambleIdentityChanged: !bytesIdentical(packed, scrambled),
    lanesOccupied: allLanes.size,
    allLanesReassembled,
    blockCountMatch: ingestOrig.blocks.length === ingestScram.blocks.length,
    rowCountMatch: matOrig.params.length === matScram.params.length,
    entityHashDiffers,
    throughputMBs: (packed.length * 2) / 1024 / 1024 / (elapsedMs / 1000), // 2x for orig + scrambled
  };
}

// ─── Run over the corpus ─────────────────────────────────────────────

console.log('# Scrambled FASTA Reassembly — Real Cancer-Gene Corpus');
console.log('');
console.log(`Source: \`open-source/bitwise/datasets/cancer-genes/fasta/\` (${basename(FASTA_DIR)})`);
console.log(`Lanes: k=${K}`);
console.log(`Scramble seed: ${SCRAMBLE_SEED}`);
console.log(`Node ${process.versions.node} on ${process.platform}/${process.arch}`);
console.log('');

const files = readdirSync(FASTA_DIR)
  .filter((f) => f.endsWith('.fasta'))
  .sort()
  .map((f) => join(FASTA_DIR, f));

console.log(`## Per-gene results (${files.length} cancer genes)`);
console.log('');
console.log('| Gene | Bases | Packed B | Scrambled ≠ Original | Lanes | All lanes reassemble | Block count match | DuckDB row match | Entity hash diverges | Throughput (orig+scram) |');
console.log('|------|------:|---------:|:---------------------:|------:|:--------------------:|:-----------------:|:----------------:|:--------------------:|------------------------:|');

const results: GeneResult[] = [];
let allPass = true;
let totalBases = 0;
let totalPackedBytes = 0;
let totalMs = 0;

for (const f of files) {
  const r = processGene(f);
  results.push(r);
  totalBases += r.bases;
  totalPackedBytes += r.packedBytes;
  totalMs += (r.packedBytes * 2) / 1024 / 1024 / r.throughputMBs * 1000;
  const geneOk =
    r.scrambleIdentityChanged &&
    r.allLanesReassembled &&
    r.blockCountMatch &&
    r.rowCountMatch &&
    r.entityHashDiffers;
  if (!geneOk) allPass = false;
  console.log(
    `| **${r.name}** | ${r.bases.toLocaleString()} | ${r.packedBytes.toLocaleString()} | ${r.scrambleIdentityChanged ? '✓' : '✗'} | ${r.lanesOccupied} | ${r.allLanesReassembled ? '✓' : '✗'} | ${r.blockCountMatch ? '✓' : '✗'} | ${r.rowCountMatch ? '✓' : '✗'} | ${r.entityHashDiffers ? '✓' : '✗'} | ${r.throughputMBs.toFixed(2)} MB/s |`,
  );
}

console.log('');
console.log('## Aggregate');
console.log('');
console.log(`- Genes processed: **${files.length}**`);
console.log(`- Total bases: **${totalBases.toLocaleString()}**`);
console.log(`- Total packed bytes: **${totalPackedBytes.toLocaleString()}** (${(totalPackedBytes / 1024).toFixed(1)} KB)`);
console.log(`- All-lanes reassembly: **${results.every((r) => r.allLanesReassembled) ? 'YES' : 'NO'}** (expect YES)`);
console.log(`- Block-count parity: **${results.every((r) => r.blockCountMatch) ? 'YES' : 'NO'}** (expect YES)`);
console.log(`- DuckDB row-count parity: **${results.every((r) => r.rowCountMatch) ? 'YES' : 'NO'}** (expect YES)`);
console.log(`- Entity-hash divergence (per-block content hash): **${results.every((r) => r.entityHashDiffers || r.packedBytes < 16) ? 'YES (where ≥16B)' : 'partial'}**`);
console.log('');

const avgThroughput = results.reduce((acc, r) => acc + r.throughputMBs, 0) / results.length;
console.log(`- Average throughput (orig + scrambled, end-to-end): **${avgThroughput.toFixed(2)} MB/s**`);
console.log('');

console.log('## Verdict');
console.log('');
if (allPass) {
  console.log('**PASS** — Every cancer-gene FASTA reassembles identically at the lane level under');
  console.log('byte-order scrambling. The wire protocol is permutation-invariant: scrambled input');
  console.log('produces the same settled lane-byte multisets, the same knotgraph block count, the');
  console.log('same DuckDB row projection, and differs only in the per-block content hash (which');
  console.log('correctly encodes within-lane byte order).');
  console.log('');
  console.log('Data delegated to geometry. Shape recovered from content. ✓');
} else {
  console.log('**FAIL** — At least one gene did not reassemble. See per-row results above.');
  process.exit(1);
}
